/// <summary>
/// Service class for creating an unsold journal in the ETGSPAIN model.
/// This service handles the creation of the journal and its transactions.
/// </summary>
class ETGSPAINUnsoldJournalCreateService extends SysOperationServiceBase
{
}

Method.Source:
/// <summary>
/// Process method to create an unsold journal based on the contract parameters.
/// </summary>
/// <param name="_contract">Contract object containing the reference record ID and unsold quantity.</param>
public void process(ETGSPAINUnsoldJournalCreateContract _contract)
{
    ETGSPAINUnsoldJournalCreateService::createJournal(_contract.parmRefRecId(), _contract.parmETGSPAINUnsoldQty());
}

    /// <summary>
    /// Creates a new unsold journal and its related transactions.
    /// </summary>
    /// <param name="_refRecId">The reference record ID used to find the unsold inventory transaction.</param>
    /// <param name="_etgspainUnsoldQty">The unsold quantity to be recorded.</param>
    /// <returns>Returns the created Unsold Journal ID.</returns>
    public static ETGSPAINUnsoldJournalId createJournal(RefRecId _refRecId, ETGSPAINUnsoldQty _etgspainUnsoldQty)
	{
        ttsbegin;
        ETGSPAINUnsoldJournalTable  etgspainUnsoldJournalTable;

        etgspainUnsoldJournalTable.clear();
        etgspainUnsoldJournalTable.initValue();

        etgspainUnsoldJournalTable.insert();

        ETGSPAINUnsoldJournalTrans  etgspainUnsoldJournalTrans;
        ETGSPAINUnsoldInventTrans   etgspainUnsoldInventTrans = ETGSPAINUnsoldInventTrans::findRefRecId(_refRecId, true);

        etgspainUnsoldJournalTrans.clear();
        etgspainUnsoldJournalTrans.initValue();

        etgspainUnsoldJournalTrans.initFromETGSPAINUnsoldJournalTable(etgspainUnsoldJournalTable);
        etgspainUnsoldJournalTrans.initFromETGSPAINUnsoldInventTrans(etgspainUnsoldInventTrans);

        etgspainUnsoldJournalTrans.MaxUnsoldQty = etgspainUnsoldInventTrans.MaxUnsoldQty;
        etgspainUnsoldJournalTrans.UnsoldQty    = _etgspainUnsoldQty;

        etgspainUnsoldJournalTrans.insert();        
        ttscommit;

        return etgspainUnsoldJournalTable.JournalId;
	}
